<?php require_once 'config/db.php'; if(!isLoggedIn() || !isClient()) redirect('login.php');
$userId = $_SESSION['user_id'];
$account = getUserAccount($pdo, $userId);
$balance = $account['AvailableBalance'] ?? 0;
$card = $pdo->prepare("SELECT * FROM CARDS WHERE CustomerID = ?"); $card->execute([$userId]); $cardData = $card->fetch();
$transactions = $pdo->prepare("SELECT t.*, tt.TypeName FROM TRANSACTION t JOIN TRANSACTIONTYPE tt ON t.TransactionTypeID=tt.TransactionTypeID WHERE t.FromCustomerID=? OR t.ToCustomerID=? ORDER BY t.TransactionDate DESC LIMIT 10");
$transactions->execute([$userId,$userId]); $transactionsData = $transactions->fetchAll();
if(isset($_GET['lang'])) { $_SESSION['language'] = $_GET['lang']; redirect('dashboard.php'); }
?>
