oard</a><a href="transfer.php" class="sidebar-item"><svg width="14" height="14" viewBox="0 0 16 16"><path d="M2 8h12M10 5l3 3-3 3" stroke="currentColor" stroke-width="1.2"/></svg>Transfer</a><a href="deposit.php" class="sidebar-item"><svg width="14" height="14" viewBox="0 0 16 16"><path d="M8 12V4M4 8l4-4 4 4" stroke="currentColor" stroke-width="1.2"/></svg>Deposit</a><a href="withdraw.php" class="sidebar-item"><svg width="14" height="14" viewBox="0 0 16 16"><path d="M8 4v8M4 8l4 4 4-4" stroke="currentColor" stroke-width="1.2"/></svg>Withdraw</a><a href="profile.php" class="sidebar-item"><svg width="14" height="14" viewBox="0 0 16 16"><circle cx="8" cy="5" r="3" stroke="currentColor"/><path d="M2 14c0-3.3 2.7-5 6-5s6 1.7 6 5" stroke="currentColor"/></svg>Nominee</a></div></div><div class="main-panel"><div class="stat-row"><div class="stat-card"><div class="stat-label">Balance</div><div class="stat-value"><?= formatBDT($balance) ?></div></div><div class="stat-card"><div class="stat-label">Account No</div><div class="stat-value">****<?= substr($account['AccountNumber'], -4) ?></div></div><div class="stat-card"><div class="stat-label">Status</div><div class="stat-value">Active</div></div></div><div class="balance-card" id="balanceCard" style="cursor:pointer"><div class="balance-amount"><?= formatBDT($balance) ?></div><div class="balance-acct">Account: <?= $account['AccountNumber'] ?></div><div class="quick-actions"><a href="transfer.php" class="qa-btn primary-btn">Transfer</a><a href="deposit.php" class="qa-btn">Deposit</a><a href="withdraw.php" class="qa-btn">Withdraw</a></div></div><div class="txn-card"><div class="txn-header"><div class="txn-title">Recent Transactions</div></div><?php foreach($transactionsData as $txn): ?><div class="txn-row"><div class="txn-icon <?= $txn['TypeName']=='Deposit'?'deposit':'transfer'?>" style="background:<?= $txn['TypeName']=='Deposit'?'var(--success-bg)':'var(--accent-bg)'?>"><?= $txn['TypeName']=='Deposit'?'+':'↗'?></div><div class="txn-info"><div class="txn-name"><?= $txn['TypeName'] ?></div><div class="txn-meta"><?= date('d M Y', strtotime($txn['TransactionDate'])) ?></div></div><div class="txn-amount" style="color:<?= $txn['FromCustomerID']==$userId?'var(--danger)':'var(--success)'?>"><?= $txn['FromCustomerID']==$userId?'-':'+'?> <?= formatBDT($txn['TransactionAmount']) ?></div><div><span class="chip chip-success"><?= $txn['TransactionStatus'] ?></span></div></div><?php endforeach; ?></div></div></div></div><div id="cardModal" class="modal"><div class="modal-content"><span class="close-modal">&times;</span><h3>Card Details</h3><?php if($cardData): ?><p><strong>Card:</strong> **** **** **** <?= substr($cardData['CardNumber'], -4) ?></p><p><strong>Expiry:</strong> <?= date('m/Y', strtotime($cardData['ExpiryDate'])) ?></p><p><strong>CVV:</strong> ***</p><?php else: ?><p>No card issued</p><?php endif; ?></div></div><div id="toastContainer"><?php $toast=getToast(); if($toast): ?><div class="toast" style="position:fixed;bottom:20px;right:20px;background:var(--color-background-primary);padding:10px 16px;border-radius:10px"><?= $toast['message'] ?></div><?php endif; ?></div><script>document.getElementById('balanceCard')?.addEventListener('click',()=>{document.getElementById('cardModal').style.display='flex';});document.querySelector('.close-modal')?.addEventListener('click',()=>{document.getElementById('cardModal').style.display='none';});window.addEventListener('click',(e)=>{if(e.target===document.getElementById('cardModal'))document.getElementById('cardModal').style.display='none';});let isDark=localStorage.getItem('theme')==='dark';function toggleTheme(){isDark=!isDark;if(isDark)document.body.classList.add('dark');else document.body.classList.remove('dark');localStorage.setItem('theme',isDark?'dark':'light');}document.getElementById('themeToggle')?.addEventListener('click',toggleTheme);if(localStorage.getItem('theme')==='dark')document.body.classList.add('dark');</script></body></html>